/*******************/
/* PAYE Validation */
/*******************/
INPUTS ARE a_terms (number_number),
           t_pay_freq (text),
           t_tax_basis(text)

dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Entering')
/***************************/
/* Check distinct pay freq */
/***************************/
dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Check payroll frequency')
idx_term = a_terms.first(-1)
a_payrolls = EMPTY_NUMBER_TEXT
t_payroll  = ' '
WHILE (a_terms.exists(idx_term)) LOOP
(
  CHANGE_CONTEXTS(PAYROLL_TERM_ID = a_terms[idx_term])
  (
     t_pay = TERM_PAYROLL_PERIOD_TYPE
     IF (a_payrolls.exists(t_pay[1])) THEN
     (
       a_payrolls[t_pay[1]] = a_payrolls[t_pay[1]] + 1
     ) ELSE (
       a_payrolls[t_pay[1]] = 1
       t_payroll = t_pay[1]
     )
  )
  idx_term = a_terms.next(idx_term, -1)
)
IF (t_pay_freq = ' ' and a_payrolls.count > 1) THEN
(
  dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Error multiple pay freq detected : ' || to_char(a_payrolls.count))
  dummy = PAY_LOG_ERROR('HRX:HRX_GBCMN_PAYE_REQ_PAYFREQ_P')
)

/***********************************/
/* Check if Override Freq is Valid */
/***********************************/
dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Checking valid payroll frequency')
IF (t_pay_freq <> ' ') THEN
(
   IF (not a_payrolls.exists(t_pay_freq)) THEN
   (
      dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Invalid payroll frequency : ' || t_pay_freq)
      dummy = PAY_LOG_ERROR('HRX:HRX_GBCMN_PAYE_INV_PAYFREQ')
   )

)

/*******************/
/* Check Tax Basis */
/*******************/
dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Checking tax basis')
IF (t_tax_basis <> 'C' and t_tax_basis <> 'N') THEN
(
   dummy = PAY_INTERNAL_LOG_WRITE('PAYE :: Invalid tax basis : ' || t_tax_basis)
   dummy = PAY_LOG_ERROR('HRX:HRX_GBCMN_INV_TAX_BASIS')
)

dummy = PAY_INTERNAL_LOG_WRITE('PAYE Validation :: Leaving')
return t_payroll

