dummy = PAY_INTERNAL_LOG_WRITE('l_run_type'|| l_run_type)
IF ((l_run_type = 'ODREG') OR (l_run_type = 'ODSPA') OR (l_run_type = 'RETNOR')) THEN
(
  l_skip = 1
  dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: OnDemandRun, skip NI/PAYE Check')
)

l_prl_license = PAYROLL_LICENSE
dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: GB_PAYROLL_LICENSE : ' || l_prl_license)
dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: GB_SKIP_PAYE_NI_CHECK_'|| to_char(l_rel_action_id) || ' : ' || to_char(l_skip))
dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: GB_PAYE_PROCESSED_REL_NOCB_RUN : '|| to_char(GB_PAYE_PROCESSED_REL_NOCB_RUN))

IF (l_skip < 1 and GB_PAYE_PROCESSED_REL_NOCB_RUN < 1 and l_prl_license = 'PAY') THEN
(
    dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: No Tax and NI processed!!')
    dummy = PAY_LOG_ERROR('HRX:HRX_GBCMN_PAYE_NI_ELE_ETRY_REQ')
)
dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: Executing ORA_HRX_GB_FPS_BAL_CHK')
EXECUTE('ORA_HRX_GB_FPS_BAL_CHK') 
dummy = PAY_INTERNAL_LOG_WRITE('GB Legislative Check :: Leaving')

